// // This module implements a synchronous RAM with a 16-bit address and an 8-bit data bus. Writing to memory is enabled when the read enable (re) signal is asserted, and reading from memory is enabled when the write enable (we) signal is asserted.
module top_module(
  input clk,

  input [15:0] a,

  input [7:0] d,
  input we,
  input re,
  output reg [7:0] q);reg [7:0] store[0:32767] ;

  always @(posedge clk)
    if (we) begin
      store[a[14:0]] <= d;
    end else if (re)
      q <= store[a[14:0]];
endmodule
